module top_module(
    input not_a,
    input b,
    output w
);
    assign w = ~not_a | b;
endmodule

module B(
    input not_a,
    input b,
    output w
);
    assign w = (~not_a & b) | (not_a & ~b);
endmodule

module top_module(
    input not_a,
    input b,
    output w
);
    wire a1_out, a2_out, b1_out, b2_out;
    wire and_out, xor_out, or_out;

    A a1(.not_a(not_a), .b(b), .w(a1_out));
    A a2(.not_a(not_a), .b(b), .w(a2_out));
    B b1(.not_a(not_a), .b(b), .w(b1_out));
    B b2(.not_a(not_a), .b(b), .w(b2_out));

    assign and_out = a1_out & b1_out;
    assign xor_out = a2_out ^ b2_out;
    assign w = and_out | xor_out;
endmodule
